'>\r\n     <h2>{KONST_POZNAMKY_OBJEDNATELE}</h2>\r\n      <br><br>\r\n        {POSTFIX}        \r\n\r\n    </td>\r\n</tr>\r\n</table>\r\n<div class=\'polozky\'><br>\r\n{KONTS_POLOZKY_PREDAVKY}\r\n      <br><br>\r\n{POLOZKY}\r\n</div>\r\n<table width=\'100%\'>\r\n<tr>\r\n    <td width=\'50%\' valign=\'top\' align=\'left\'>\r\n        <br><br><br><br><br><br><br><br>\r\n        {PODPIS_PREDAVAJICI}\r\n    </td>\r\n    <td width=\'50%\' valign=\'top\' align=\'left\'>\r\n        <br><br><br><br><br><br><br><br>\r\n        {PODPIS_PREBIRAJICI}     \r\n        {DIGI_PODPIS_PREBIRAJICI}   \r\n    </td>\r\n</tr>\r\n</table>\r\n</body>\r\n</html>', '.color1{\r\n    background-color: #1976d2;\r\n    color: #fff;\r\n}\r\n\r\n.color2{\r\n    background-color:  #f5f5f5;\r\n    color: #757575;\r\n}\r\n\r\nbody {\r\n\r\n    font-size: 10px;\r\n    color: #757575;\r\n    font-family:Arial\r\n}\r\n\r\nimg.company-logo{\r\n    height: 75px;\r\n    max-width: 250px;\r\n}\r\n.casove-razitko{\r\n    padding-left: 80px;\r\n    text-align:center;\r\n    display:block;\r\n    font-size: 8px;\r\n}\r\n.doc-header{\r\n    padding: 15px;\r\n    font-size: 11px;\r\n}\r\n\r\n  h1{\r\n    font-weight: bold;\r\n    font-size: 15px;\r\n\r\n}\r\n\r\n.hlavicka{\r\n    padding: 15px;\r\n\r\n}\r\n\r\nh2{\r\n    font-size: 14px;\r\n}\r\n\r\nstrong{\r\n    color: #000;\r\n}\r\n\r\n.odberatel{\r\n    border-left: 1px solid #f5f5f5;\r\n    \r\n}\r\n.dodavatel{\r\n \r\n}\r\n\r\ntable.souhrn{\r\nmargin-top: 50px;\r\nwidth: 100%;\r\nborder-collapse: collapse;\r\n\r\n}\r\n\r\ntable.products{\r\nborder-collapse: collapse;\r\n}\r\n\r\ntable.products td{\r\npadding-top: 5px; padding-bottom:5px;\r\n border-top: 1px solid #1976d2;\r\n\r\n}\r\n\r\ntable.souhrn td{\r\n border-top: 1px solid #1976d2;\r\n padding-top: 5px; padding-bottom: 5px;\r\n border-collapse: collapse;\r\n}\r\n#reverseCharge{\r\ndisplay: block;\r\nfont-size: 10px;\r\nmargin-top: 30px;\r\nmargin-bottom: 30px;\r\n}\r\ndiv.finalSum{\r\nfont-size: 15px;\r\ncolor: #1976d2;\r\n\r\n}\r\n ', 1);
