INSERT INTO `partners` (`id`, `id_parent`, `id_user`, `code`, `name`, `ic`, `dic`, `relationship`, `type`, `revenue`, `sale`, `rating`, `employes`, `source`, `source_id`, `territory`, `bill_addr_state`, `bill_addr_city`, `bill_addr_street`, `bill_addr_code`, `ship_addr_state`, `ship_addr_city`, `ship_addr_street`, `ship_addr_code`, `account`, `state`, `delete`, `logo_img`, `industry`, `description`, `date_save`, `tags`) VALUES
(1, 0, 62, 'OPA-26-00001', 'Sysportal s.r.o.', '29453461', 'CZ29453461', 0, 'b2b', 0, 0.00, '5', 0, 'campaign', 0, 0, 0, 'Opava', 'Nákladní 895', '74601', 0, 'Opava', 'Nákladní 895', '74601', '', 22, '0', '', 0, 'Sysportal s.r.o. je podle svého webu dodavatel personalizovaného CRM a softwaru pro řízení zakázek, zaměřený především na malé a střední podniky. Produkt staví na individuálně přizpůsobeném řešení místo krabicového software; každý zákazník má vlastní instanci aplikace, což firmě umožňuje upravovat funkcionalitu podle konkrétních procesů klienta. Systém pokrývá správu obchodních partnerů a zákazníků, plánovací kalendář a aktivity, obchodní případy, nabídky a objednávky, projektové a zakázkové řízení, sledování nákladů a ziskovosti, úkoly, Ganttův diagram, Kanban i fakturaci s exportem do účetního software. Obchodně je řešení profilované pro firmy, které potřebují propojit CRM, obchod, realizaci zakázek a operativní řízení týmu v jednom systému; web zároveň uvádí oborová řešení pro zakázkovou výrobu, stavebnictví, řemesla a obchodní činnost. Firma zdůrazňuje přizpůsobení na míru, poimplementační podporu a více než 10 let zkušeností.', 1772800711, ''),
(2, 0, 62, 'OPA-26-00002', 'Time & Data s.r.o.', '22541748', 'CZ22541748', 0, 'b2b', 0, 0.00, '5', 0, 'campaign', 0, 0, 0, 'Praha', 'Dlouhá 730', '11000', 0, 'Praha', 'Dlouhá 730', '11000', '', 22, '0', '', 0, 'Time & Data s.r.o. je dodavatel a integrátor přístupových, komunikačních a turniketových systémů, který se podle svého webu věnuje distribuci, instalaci a návrhu řešení v oblasti audiovrátníků, videovrátníků, přístupových systémů, turniketů a souvisejících inteligentních systémů. Firma se specializuje zejména na elektronické uzamykací a vstupní technologie pro bytové domy, ubytovací zařízení, fitness a wellness centra, vzdělávací instituce, sportovní areály a průmyslové provozy; současně nabízí dodávky „na klíč“, velkoobchod pro montážní firmy, technické poradenství, školení i záruční a pozáruční servis. Obchodně působí jako partner pro investory i instalační firmy, kde zdůrazňuje technickou podporu, individuální návrh řešení a přímý dovoz od výrobců. Na webu má viditelné konkrétní reference z let 2023–2025, například FEI STU v Bratislavě, Letní koupaliště Litoměřice, Koupaliště Cihelna Pardubice, centrum Na Fialce v Říčanech, Národné padelové centrum v Bratislavě nebo fitness projekty Spartan Gym a HM Fit, což podporuje důvěryhodnost zejména ve segmentech sportovišť, škol a řízeného vstupu do budov.', 1772807811, '');
