(2, 62, 62, 1, 1764547200, 1764547200, 'Obhlídka', '', 55, 0, 0, '', 100, 'purple', 1764547200, 1764547200),
(3, 62, 62, 1, 1765152000, 1765756800, 'Vypracování projektové dokumentace', 'Projekt byl vypracován ve třech vyhotoveních. Máme zakreslený skutečný stav, plány pro realizaci a projekt skutečného stavu po realizaci. Dále připraven podklad pro výrobu rozvaděče a podklad pro výchozí revizi. ', 55, 1, 0, ';projekt', 100, 'indigo', 1765152000, 1765756800),
