(7, 62, 62, 1, 1767571200, 1768176000, 'Výroba rozvaděče', 'Rozvaděč připraven k instalaci vč. střídače ', 55, 0, 0, '', 100, 'purple', 1767571200, 1768176000),
(8, 62, 62, 1, 1769990400, 1770163200, 'Zapojení a spuštění', 'Při testu se objevili nespecifikované komplikace. Vyhazuje nám hlavní jistič. ', 136, 0, 0, '', 50, 'red', 1769990400, 1770163200),
